import { type KeyboardEvent as ReactKeyboardEvent, useRef } from 'react';
import { useIntl } from 'react-intl';

import { DownloadIcon } from '@dynatrace/strato-icons';

import { ChartToolbarRenderer } from '../../../../core/components/toolbar/ChartToolbarRenderer.js';
import { useA11yToolbarTabIndex } from '../../../../core/hooks/useA11yToolbarTabIndex.js';
import { usePieChartRawData } from '../../../context/PieChartRawDataContext.js';
import { PIE_CHART_MESSAGES } from '../../../messages.js';
import { buildAndDownloadCsv } from '../../../utils/build-and-download-csv.js';

export const DownloadDataButton = () => {
  const downloadDataButtonRef = useRef<HTMLButtonElement>(null);
  const tabIndex = useA11yToolbarTabIndex('download');
  const intl = useIntl();
  const rawData = usePieChartRawData();

  /** Handles the download button when event keydown.*/
  const handleDownloadDataKeyboard = (event: ReactKeyboardEvent) => {
    if (event.key === 'Enter') {
      buildAndDownloadCsv(rawData);
    }
  };

  /** Handles the download button when clicked. */
  const handleDownloadDataToolbar = () => {
    buildAndDownloadCsv(rawData);
  };

  return (
    <ChartToolbarRenderer.Control
      ref={downloadDataButtonRef}
      prefixIcon={<DownloadIcon />}
      tooltipText={intl.formatMessage(PIE_CHART_MESSAGES.downloadAsCsv)}
      testId="chart-toolbar-download"
      onKeyDown={handleDownloadDataKeyboard}
      onClick={handleDownloadDataToolbar}
      tabIndex={tabIndex}
    />
  );
};

DownloadDataButton['displayName'] = 'DownloadDataButton';
